import{_ as t,o as l,c as e,ag as i}from"./chunks/framework.BqfgOMAh.js";const p=JSON.parse('{"title":"故障排除","description":"","frontmatter":{},"headers":[],"relativePath":"zh/faq/troubleshooting.md","filePath":"zh/faq/troubleshooting.md"}'),s={name:"zh/faq/troubleshooting.md"};function r(n,o,a,d,g,u){return l(),e("div",null,[...o[0]||(o[0]=[i('<h1 id="故障排除" tabindex="-1">故障排除 <a class="header-anchor" href="#故障排除" aria-label="Permalink to &quot;故障排除&quot;">​</a></h1><p>本页面提供常见问题的详细诊断步骤。如果你遇到的问题比较简单，建议先查看 <a href="./">常见问题</a>。</p><h2 id="无法连接-ue-编辑器" tabindex="-1">无法连接 UE 编辑器 <a class="header-anchor" href="#无法连接-ue-编辑器" aria-label="Permalink to &quot;无法连接 UE 编辑器&quot;">​</a></h2><p><strong>症状</strong>：NexusFlow 状态栏始终显示 🔴 红色未连接状态，即使 UE 编辑器已启动。</p><p><strong>可能原因</strong>：</p><ul><li>NexusFlow 桌面应用与 UE 插件版本不匹配</li><li>UE 项目中未启用 NexusFlow 插件</li><li>防火墙或安全软件阻止通信</li><li>另一个 NexusFlow 实例占用了通信管道</li></ul><p><strong>诊断步骤</strong>：</p><ol><li><strong>检查版本匹配</strong>：确保 NexusFlow 桌面应用和 UE 插件都更新到最新版本，版本不匹配是最常见的连接失败原因</li><li><strong>检查插件状态</strong>：在 UE 中打开 编辑 &gt; 插件管理器，搜索 &quot;NexusFlow&quot;，确认插件已启用</li><li><strong>排除防火墙干扰</strong>：暂时关闭防火墙或安全软件，测试连接</li><li><strong>检查多实例</strong>：确保只有一个 NexusFlow 在运行（查看任务管理器）</li><li><strong>查看日志</strong>： <ul><li>NexusFlow 日志：<code>%APPDATA%/cn.nexusflow.desktop/logs/tauri_debug.log</code></li><li>UE 日志：<code>&lt;项目目录&gt;/Saved/Logs/</code> 目录下，搜索关键字 <code>LogNexusFlow</code></li></ul></li><li><strong>重启两端</strong>：关闭 UE 和 NexusFlow，然后重新启动（启动顺序不限）</li></ol><div class="tip custom-block"><p class="custom-block-title">快速检查</p><p>打开 NexusFlow 的 设置 &gt; 关于 页面，查看「插件状态」部分是否检测到 UE 安装。</p></div><h2 id="ai-无响应或报错" tabindex="-1">AI 无响应或报错 <a class="header-anchor" href="#ai-无响应或报错" aria-label="Permalink to &quot;AI 无响应或报错&quot;">​</a></h2><p><strong>症状</strong>：发送消息后 AI 没有回复，或对话区域显示错误信息。</p><p><strong>可能原因</strong>：</p><ul><li>AI 模型未配置或验证失败</li><li>API Key 无效或余额不足</li><li>网络无法访问 AI 服务端点</li><li>Custom Provider 配置错误</li></ul><p><strong>诊断步骤</strong>：</p><ol><li><strong>检查模型配置</strong>：进入 设置 &gt; AI 模型，确认已添加至少一个模型并设为默认</li><li><strong>测试模型连接</strong>：点击模型卡片上的「验证」按钮</li><li><strong>如果验证失败</strong>： <ul><li>检查 API Key 是否正确复制（注意首尾空格）</li><li>检查服务商账户余额是否充足</li><li>测试网络连通性： <ul><li>OpenAI：能否访问 <code>api.openai.com</code></li><li>Anthropic：能否访问 <code>api.anthropic.com</code></li><li>DeepSeek：能否访问 <code>api.deepseek.com</code></li><li>智谱 GLM：能否访问 <code>open.bigmodel.cn</code></li><li>MiniMax：能否访问 <code>api.minimaxi.com</code></li><li>通义千问：能否访问 <code>dashscope.aliyuncs.com</code></li><li>Kimi：能否访问 <code>api.moonshot.cn</code></li></ul></li></ul></li><li><strong>如果使用 Custom Provider</strong>：确认 API 地址和通讯协议选择正确</li><li><strong>查看日志</strong>：打开 <code>%APPDATA%/cn.nexusflow.desktop/logs/tauri_debug.log</code>，搜索 <code>error</code> 或 <code>failed</code></li></ol><div class="warning custom-block"><p class="custom-block-title">Anthropic 用户注意</p><p>Anthropic (Claude) 模型<strong>必须设置 Max Tokens</strong>，否则 API 调用会失败。进入模型配置检查此项。</p></div><h2 id="侧边栏对话功能长时间不可用" tabindex="-1">侧边栏对话功能长时间不可用 <a class="header-anchor" href="#侧边栏对话功能长时间不可用" aria-label="Permalink to &quot;侧边栏对话功能长时间不可用&quot;">​</a></h2><p><strong>症状</strong>：打开侧边栏后，对话输入框长时间处于不可用状态或加载中。</p><p><strong>可能原因</strong>：</p><ul><li>AI 服务内部初始化延迟</li><li>端口被其他 NexusFlow 实例或程序占用</li></ul><p><strong>诊断步骤</strong>：</p><ol><li><strong>等待初始化</strong>：首次打开时，AI 服务需要约 10 秒完成初始化，期间会自动重试</li><li><strong>检查多实例</strong>：在任务管理器中搜索 &quot;NexusFlow&quot;，关闭多余的实例</li><li><strong>检查端口冲突</strong>：是否有其他程序占用了随机端口</li><li><strong>重启应用</strong>：完全关闭 NexusFlow 后重新启动</li></ol><h2 id="蓝图操作后出现异常" tabindex="-1">蓝图操作后出现异常 <a class="header-anchor" href="#蓝图操作后出现异常" aria-label="Permalink to &quot;蓝图操作后出现异常&quot;">​</a></h2><p><strong>症状</strong>：AI 操作蓝图后，蓝图出现编译错误、连线断开或行为异常。</p><p><strong>可能原因</strong>：</p><ul><li>AI 生成的操作不一定总是完美的</li><li>可能产生无效连线或缺少必要节点</li><li>复杂蓝图的操作可能不够精确</li></ul><p><strong>诊断步骤</strong>：</p><ol><li><strong>立即撤销</strong>：在 UE 中按 <code>Ctrl+Z</code> 撤销最近的操作</li><li><strong>检查错误信息</strong>：查看蓝图编译器给出的具体错误提示</li><li><strong>多次撤销</strong>：如果一次撤销不够，多按几次 <code>Ctrl+Z</code> 回退更多步骤</li><li><strong>版本控制恢复</strong>：如果撤销无效，从 Git 或其他版本控制系统恢复文件</li></ol><div class="danger custom-block"><p class="custom-block-title">重要提醒</p><p>在让 AI 执行重要的蓝图修改前，建议先<strong>保存蓝图</strong>（<code>Ctrl+S</code>）。这样即使出现问题，也可以通过撤销回到保存点。</p></div><p><strong>预防措施</strong>：</p><ul><li>对重要蓝图操作前先保存</li><li>使用版本控制系统（如 Git）管理蓝图文件</li><li>分步操作，避免一次性执行过多修改</li><li>在对话中描述需求时尽量具体</li></ul><h2 id="全局快捷键不工作" tabindex="-1">全局快捷键不工作 <a class="header-anchor" href="#全局快捷键不工作" aria-label="Permalink to &quot;全局快捷键不工作&quot;">​</a></h2><p><strong>症状</strong>：设置了全局快捷键（如切换侧边栏）但按下后没有反应。</p><p><strong>可能原因</strong>：</p><ul><li>快捷键与其他应用冲突</li><li>快捷键注册到操作系统失败</li><li>修改后未重启应用</li></ul><p><strong>诊断步骤</strong>：</p><ol><li><strong>检查冲突</strong>：确认没有其他应用（如截图工具、输入法等）占用相同的快捷键</li><li><strong>更换组合键</strong>：进入 设置 &gt; 快捷键，尝试换一个不常用的组合</li><li><strong>恢复默认</strong>：点击「恢复默认」按钮重置所有快捷键</li><li><strong>重启应用</strong>：修改快捷键后<strong>重启 NexusFlow</strong> 使其生效</li></ol><h2 id="日志文件位置" tabindex="-1">日志文件位置 <a class="header-anchor" href="#日志文件位置" aria-label="Permalink to &quot;日志文件位置&quot;">​</a></h2><p>排查问题时，日志文件是最重要的诊断信息来源。</p><h3 id="nexusflow-日志" tabindex="-1">NexusFlow 日志 <a class="header-anchor" href="#nexusflow-日志" aria-label="Permalink to &quot;NexusFlow 日志&quot;">​</a></h3><table tabindex="0"><thead><tr><th>日志</th><th>路径</th></tr></thead><tbody><tr><td>主程序日志</td><td><code>%APPDATA%/cn.nexusflow.desktop/logs/tauri_debug.log</code></td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">打开 AppData 目录</p><p>在 Windows 文件资源管理器的地址栏输入 <code>%APPDATA%/cn.nexusflow.desktop/</code> 按回车即可快速打开。</p></div><h3 id="ue-插件日志" tabindex="-1">UE 插件日志 <a class="header-anchor" href="#ue-插件日志" aria-label="Permalink to &quot;UE 插件日志&quot;">​</a></h3><table tabindex="0"><thead><tr><th>日志</th><th>路径</th></tr></thead><tbody><tr><td>UE 编辑器日志</td><td><code>&lt;UE 项目目录&gt;/Saved/Logs/*.log</code></td></tr><tr><td>Bridge 调试日志（Debug 构建）</td><td><code>&lt;UE 项目目录&gt;/Saved/Logs/nexusflow_bridge_debug.log</code></td></tr></tbody></table><ul><li>在 UE 日志中搜索关键字 <strong><code>LogNexusFlow</code></strong> 可以过滤出 NexusFlow 插件相关的日志</li><li>Bridge 调试日志仅在 Debug 构建中生成；Release 构建的 Bridge 日志合并在 UE 标准日志中，搜索 <strong><code>[Bridge]</code></strong> 关键字</li></ul><h2 id="ue-中弹出-nexusflow-setup-对话框" tabindex="-1">UE 中弹出 NexusFlow Setup 对话框 <a class="header-anchor" href="#ue-中弹出-nexusflow-setup-对话框" aria-label="Permalink to &quot;UE 中弹出 NexusFlow Setup 对话框&quot;">​</a></h2><p><strong>现象</strong>：每次启动 UE 编辑器时，都会弹出 &quot;NexusFlow Setup&quot; 对话框。</p><p><strong>说明</strong>：当 NexusFlow 插件检测到桌面应用未安装或 Embedding 模型未就绪时，会弹出此对话框。这是首次运行帮助，不是报错。</p><p><strong>处理方式</strong>：</p><table tabindex="0"><thead><tr><th>你想…</th><th>操作</th></tr></thead><tbody><tr><td>现在配置</td><td>点击 <strong>Download Model</strong> 或 <strong>Open Settings</strong>，按提示操作</td></tr><tr><td>稍后配置</td><td>点击 <strong>Later</strong>，下次启动仍会提示</td></tr><tr><td>永不再显示</td><td>点击 <strong>Don&#39;t Show Again</strong>，对话框将不再出现</td></tr></tbody></table><p><strong>关闭后想重新启用</strong>：</p><ol><li>打开 <code>%LOCALAPPDATA%/NexusFlow/config.json</code></li><li>将 <code>&quot;showSetupWizard&quot;</code> 改为 <code>true</code></li><li>重启 UE 编辑器</li></ol><h2 id="仍然无法解决" tabindex="-1">仍然无法解决？ <a class="header-anchor" href="#仍然无法解决" aria-label="Permalink to &quot;仍然无法解决？&quot;">​</a></h2><p>如果以上步骤都没有解决你的问题：</p><ol><li>收集相关日志文件（NexusFlow 日志 + UE 日志）</li><li>记录问题的复现步骤</li><li>在 <a href="https://github.com/maxzhao/NexusFlow/issues" target="_blank" rel="noreferrer">GitHub Issues</a> 提交问题，附上以上信息</li></ol>',55)])])}const h=t(s,[["render",r]]);export{p as __pageData,h as default};
